/// Hamming distance between two SDRs (number of differing bits).
pub fn hamming_distance(a: &Sdr, b: &Sdr) -> u32 {
    let mut dist = 0u32;
    for i in 0..SDR_WORDS {
        dist += (a[i] ^ b[i]).count_ones();
    }
    dist
}

