/// Normalized Hamming similarity: `1.0 - (distance / SDR_BITS)`.
pub fn hamming_similarity(a: &Sdr, b: &Sdr) -> f64 {
    1.0 - (hamming_distance(a, b) as f64 / SDR_BITS as f64)
}

