/// Bitwise OR of two SDRs — concept union.
pub fn or(a: &Sdr, b: &Sdr) -> Sdr {
    let mut out = ZERO;
    for i in 0..SDR_WORDS {
        out[i] = a[i] | b[i];
    }
    out
}

