/// Encode an SDR as a hex string (64 hex chars = 32 bytes, little-endian).
pub fn to_hex(sdr: &Sdr) -> String {
    let mut out = String::with_capacity(SDR_WORDS * 16);
    for word in sdr {
        for byte in word.to_le_bytes() {
            out.push_str(&format!("{byte:02x}"));
        }
    }
    out
}

