        }
        Some(trigger) => {
            tracing::info!(trigger, "unhandled webhook trigger");
        }
        None => {
            tracing::debug!("webhook with no trigger_id");
        }
    }

    (StatusCode::OK, Json(WebhookResponse::ok()))
}

