            .as_deref()
            .map(|ts| ts.get(..16).unwrap_or(ts))
            .unwrap_or("-");
        out.push_str(&format!(
            "| {} | {} | {} | {} |\n",
            entity.entity_id, friendly, entity.state, last_changed
        ));
    }

