pub async fn mesh_proxy(
    State(state): State<AppState>,
    Json(req): Json<MeshProxyRequest>,
) -> impl IntoResponse {
    match state.proxy.proxy(req).await {
        Ok(resp) => (
            StatusCode::from_u16(resp.status).unwrap_or(StatusCode::INTERNAL_SERVER_ERROR),
            Json(resp),
